function AnimatedLogoBadge({
  mobileLeft = false,
  placement = "header",
}: {
  mobileLeft?: boolean;
  placement?: "header" | "footer";
}) {
  const sizeClasses =
    placement === "footer"
      ? "h-11 max-w-[190px] sm:h-12 sm:max-w-[210px] md:h-14 md:max-w-[245px]"
      : "h-8 max-w-[138px] sm:h-[48px] sm:max-w-[220px] md:h-[76px] md:max-w-[340px] lg:h-[80px] lg:max-w-[360px]";

  return (
    <div
      className={`inline-flex items-center ${mobileLeft ? "-ml-0 sm:ml-0" : ""}`}
      aria-label="Havstraum"
    >
      <img
        src={HAVSTRAUM_LOGO_SRC}
        alt="Havstraum logo"
        width={2048}
        height={495}
        className={`${sizeClasses} w-auto object-contain`}
      />
    </div>
  );
}

function ContactModal({
  isOpen,
  form,
  onClose,
  onSubmit,
  onChange,
}: {
  isOpen: boolean;
  form: ContactFormState;
  onClose: () => void;
  onSubmit: (event: FormEvent<HTMLFormElement>) => void;
  onChange: (field: keyof ContactFormState, value: string) => void;
}) {
  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-[60] flex h-[100dvh] items-start justify-center overflow-y-auto overscroll-contain px-4 pt-4 pb-[calc(1rem+env(safe-area-inset-bottom))] sm:items-center sm:py-6"
      role="dialog"
      aria-modal="true"
      aria-labelledby="contact-modal-title"
    >
      <button
        type="button"
        aria-label="Close contact form"
        className="fixed inset-0 bg-[hsl(var(--navy-deep))]/70 backdrop-blur-sm"
        onClick={onClose}
      />

      <div className="relative z-10 w-full max-w-2xl max-h-[calc(100dvh-2rem-env(safe-area-inset-bottom))] overflow-y-auto rounded-[32px] border border-[hsl(var(--border))] bg-[hsl(var(--card))] p-5 shadow-2xl sm:max-h-[calc(100dvh-3rem)] sm:p-6 md:p-8">
        <div className="mb-5 flex items-start justify-between gap-4 sm:mb-8">
          <div>
            <p className="font-body type-section-header text-[hsl(var(--teal))] mb-3">
              Contact
            </p>
            <h3
              id="contact-modal-title"
              className="font-display type-subtitle text-[hsl(var(--fg))]"
            >
              Get Involved
            </h3>
            <p className="mt-3 max-w-xl font-body type-caption text-[hsl(var(--muted))]">
              Share your name, organisation email, and message. On submit, the
              message opens in your email app ready to send to Havstraum.
            </p>
          </div>

          <button
            type="button"
            onClick={onClose}
            className="inline-flex h-11 w-11 items-center justify-center rounded-full border border-[hsl(var(--border))] text-[hsl(var(--muted))] transition-colors hover:border-[hsl(var(--teal))]/40 hover:text-[hsl(var(--fg))]"
            aria-label="Close"
          >
            <CloseIcon className="h-5 w-5" />
          </button>
        </div>

        <form onSubmit={onSubmit} className="space-y-4 sm:space-y-5">
          <div className="grid gap-4 sm:gap-5 md:grid-cols-2">
            <label className="block">
              <span className="mb-2 block font-body type-caption font-medium text-[hsl(var(--fg))]">
                Name
              </span>
              <input
                type="text"
                value={form.name}
                onChange={(event) => onChange("name", event.target.value)}
                placeholder="Your name"
                required
                className="w-full rounded-2xl border border-[hsl(var(--border))] bg-[hsl(var(--card))] px-4 py-3 font-body type-body text-[hsl(var(--fg))] outline-none transition focus:border-[hsl(var(--teal))] focus:ring-4 focus:ring-[hsl(var(--teal))]/10"
              />
            </label>

            <label className="block">
              <span className="mb-2 block font-body type-caption font-medium text-[hsl(var(--fg))]">
                Organisation email
              </span>
              <input
                type="email"
                value={form.email}
                onChange={(event) => onChange("email", event.target.value)}
                placeholder="name@organisation.com"
                required
                className="w-full rounded-2xl border border-[hsl(var(--border))] bg-[hsl(var(--card))] px-4 py-3 font-body type-body text-[hsl(var(--fg))] outline-none transition focus:border-[hsl(var(--teal))] focus:ring-4 focus:ring-[hsl(var(--teal))]/10"
              />
            </label>
          </div>

          <label className="block">
            <span className="mb-2 block font-body type-caption font-medium text-[hsl(var(--fg))]">
              Message
            </span>
            <textarea
              value={form.message}
              onChange={(event) => onChange("message", event.target.value)}
              placeholder="Tell us a bit about your enquiry"
              rows={5}
              required
              className="w-full min-h-[140px] rounded-[24px] border border-[hsl(var(--border))] bg-[hsl(var(--card))] px-4 py-3 font-body type-body text-[hsl(var(--fg))] outline-none transition focus:border-[hsl(var(--teal))] focus:ring-4 focus:ring-[hsl(var(--teal))]/10 sm:min-h-[160px]"
            />
          </label>

          <div className="-mx-5 flex flex-col gap-3 bg-[hsl(var(--card))] px-5 pt-2 pb-[calc(0.75rem+env(safe-area-inset-bottom))] sm:mx-0 sm:flex-row sm:justify-end sm:bg-transparent sm:p-0">
            <div className="flex flex-col gap-3 sm:flex-row">
              <button
                type="button"
                onClick={onClose}
                className="inline-flex w-full items-center justify-center rounded-full border border-[hsl(var(--border))] px-6 py-3 font-body type-body font-medium text-[hsl(var(--fg))] transition hover:border-[hsl(var(--teal))]/40 hover:bg-[hsl(var(--teal))]/5 sm:w-auto"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="inline-flex w-full items-center justify-center rounded-full bg-ocean-gradient px-6 py-3 font-body type-body font-medium text-[hsl(var(--ice))] transition hover:brightness-110 sm:w-auto"
              >
                Send enquiry
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}

