function ConstraintHeadingCard({
  number,
  title,
  className = "",
}: {
  number: string;
  title: string;
  className?: string;
}) {
  return (
    <div
      className={[
        "group relative flex min-h-[250px] flex-col overflow-hidden rounded-[32px] border border-[hsl(var(--ice))]/10 bg-[linear-gradient(180deg,rgba(255,255,255,0.085),rgba(255,255,255,0.04))] p-7 md:p-8 backdrop-blur-md shadow-[0_24px_60px_rgba(0,0,0,0.18)] transition-all duration-500 hover:-translate-y-1.5 hover:border-[hsl(var(--ice))]/18 hover:shadow-[0_30px_70px_rgba(0,0,0,0.24)]",
        className,
      ].join(" ")}
    >
      <div className="absolute inset-x-7 top-0 h-px bg-gradient-to-r from-transparent via-[hsl(var(--teal))]/65 to-transparent opacity-90" />
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,rgba(31,169,195,0.12),transparent_34%)] opacity-0 transition-opacity duration-500 group-hover:opacity-100" />

      <div className="relative flex h-full flex-col">
        <div className="mb-8 flex items-start justify-between gap-4">
          <p className="font-display text-[42px] md:text-[50px] leading-none tracking-[-0.04em] text-[hsl(var(--ice))]">
            {number}
            <span className="text-[hsl(var(--teal))]">.</span>
          </p>
          <div className="mt-2 h-11 w-11 rounded-full border border-[hsl(var(--ice))]/10 bg-[hsl(var(--navy-deep))]/28" />
        </div>

        <h3 className="font-display text-[30px] md:text-[34px] font-medium leading-[1.08] tracking-[-0.03em] text-[hsl(var(--ice))] max-w-[11ch]">
          {title}
        </h3>

        <div className="mt-auto pt-10">
          <div className="h-px w-full bg-gradient-to-r from-[hsl(var(--teal))]/38 via-[hsl(var(--ice))]/10 to-transparent" />
        </div>
      </div>
    </div>
  );
}

function ContactCard({
  icon,
  title,
  description,
  onMouseMove,
  onMouseLeave,
}: {
  icon: ReactNode;
  title: string;
  description: string;
  onMouseMove?: (event: ReactMouseEvent<HTMLElement>) => void;
  onMouseLeave?: (event: ReactMouseEvent<HTMLElement>) => void;
}) {
  return (
    <div
      onMouseMove={onMouseMove}
      onMouseLeave={onMouseLeave}
      className="interactive-card flex gap-4 items-start p-6 rounded-2xl border border-[hsl(var(--border))] bg-[hsl(var(--card))] transition-all duration-300 hover:-translate-y-1 hover:border-[rgba(97,211,255,0.5)] hover:shadow-[0_22px_60px_rgba(56,189,248,0.18)]"
    >
      {icon}
      <div>
        <h3 className="font-display type-heading text-[hsl(var(--fg))] mb-1">
          {title}
        </h3>
        <p className="font-body type-caption text-[hsl(var(--muted))]">
          {description}
        </p>
      </div>
    </div>
  );
}

